/**
 * @summary Upload documents
 */
export const getUploadDocumentsUrl = () => {
  return `/api/upload`;
};

export const uploadDocuments = async (
  uploadRequest: UploadRequest,
  options?: RequestInit,
): Promise<UploadResponse> => {
  const formData = new FormData();
  uploadRequest.files.forEach((value) => formData.append(`files`, value));
  formData.append(`course`, uploadRequest.course);

  return customFetch<UploadResponse>(getUploadDocumentsUrl(), {
    ...options,
    method: "POST",
    body: formData,
  });
};

